  $lines = [System.Collections.Generic.List[string]]::new()
  [System.IO.File]::ReadAllLines($myEnv) | ForEach-Object { [void]$lines.Add($_) }
  $rugbyLines = @($lines | Where-Object { $_ -match '^RUGBY_' })
  if ($rugbyLines.Count -gt 0) {
    $existing = if (Test-Path -LiteralPath $rugbyEnv) { [System.IO.File]::ReadAllLines($rugbyEnv) } else { @() }
    $toAppend = foreach ($line in $rugbyLines) { if ($existing -notcontains $line) { $line } }
    if ($toAppend.Count -gt 0) { Add-Content -LiteralPath $rugbyEnv -Value $toAppend }
