#!/usr/bin/env node
/**
 * Rugby Guy CLI
 *
 * Usage:
 *   node scripts/run.mjs rugby sync
 *   node scripts/run.mjs rugby web
 */

import { config } from 'dotenv';
import { dirname, join, resolve } from 'path';
import { fileURLToPath } from 'url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const vaultRoot = resolve(__dirname, '..');
config({ path: join(vaultRoot, '.env') });

const [, , group, subcommand, ...args] = process.argv;
const flags = parseArgs(args);

if (!group || group === 'help' || group === '--help') {
  printHelp();
  process.exit(0);
}

if (group !== 'rugby') {
  console.error(`Unknown group "${group}". This vault only exposes the rugby command group.`);
  printHelp();
  process.exit(1);
}

try {
  await routeRugby(subcommand, flags);
} catch (err) {
  console.error(`\nError: ${err.message}`);
  if (process.env.DEBUG) console.error(err.stack);
  process.exit(1);
}

function parseArgs(rawArgs) {
  const parsed = {};
  for (let i = 0; i < rawArgs.length; i++) {
    const current = rawArgs[i];
    if (!current.startsWith('--')) continue;

    const key = current.slice(2);
    const next = rawArgs[i + 1];
    if (next && !next.startsWith('--')) {
      parsed[key] = next;
      i++;
    } else {
      parsed[key] = true;
    }
  }
  return parsed;
}

async function routeRugby(sub, flags) {
  switch (sub) {
    case 'extract': {
      const m = await import('./pullers/rugby-instagram.mjs');
      return m.pull(flags);
    }
    case 'classify': {
      const m = await import('./pullers/rugby-classify.mjs');
      return m.pull(flags);
    }
    case 'ingest': {
      const m = await import('./pullers/rugby-ingest.mjs');
      return m.pull(flags);
    }
    case 'accounts': {
      const m = await import('./pullers/rugby-accounts.mjs');
      return m.pull(flags);
    }
    case 'download': {
      const m = await import('./pullers/rugby-download.mjs');
      return m.pull(flags);
    }
    case 'web': {
      const { startServer } = await import('./dashboard/rugby-web.mjs');
      const port = parseInt(process.env.RUGBY_PORT ?? '5757', 10);
      startServer(port);
      await new Promise(() => {});
      return;
    }
    case 'publish': {
      const m = await import('./dashboard/rugby-export.mjs');
      return m.pull(flags);
    }
    case 'sync': {
      console.log('Rugby sync - running full pipeline\n');
      const extract = await import('./pullers/rugby-instagram.mjs');
      const classify = await import('./pullers/rugby-classify.mjs');
      const ingest = await import('./pullers/rugby-ingest.mjs');
      const accounts = await import('./pullers/rugby-accounts.mjs');
      await extract.pull(flags);
      await classify.pull(flags);
      await ingest.pull(flags);
      await accounts.pull(flags);
      return;
    }
    case 'status': {
      const { existsSync, readdirSync, readFileSync } = await import('fs');
      const cacheDir = join(vaultRoot, '.cache', 'rugby');
      const postsDir = join(vaultRoot, 'Rugby', 'Posts');
      const allFiles = existsSync(cacheDir) ? readdirSync(cacheDir).filter((f) => f.endsWith('.json')) : [];
      const raw = allFiles.filter((f) => !f.includes('-classified') && !f.includes('-gdrive')).length;
      const classif = allFiles.filter((f) => f.includes('-classified')).length;
      const gdrive = allFiles.filter((f) => f.includes('-gdrive')).length;
      const notes = existsSync(postsDir) ? readdirSync(postsDir).filter((f) => f.endsWith('.md')).length : 0;
      let linkCount = '?';
      try {
        const content = readFileSync(join(vaultRoot, 'Rugby', 'Rugby Links.md'), 'utf8');
        linkCount = (content.match(/instagram\.com\/(?:p|reel)\//g) ?? []).length;
      } catch {
        // Optional source file may not exist yet.
      }

      console.log('\nRugby Coach Dashboard - Status');
      console.log(`   Source URLs    : ${linkCount}`);
      console.log(`   Fetched        : ${raw}`);
      console.log(`   Classified     : ${classif}`);
      console.log(`   Uploaded (GDr) : ${gdrive}`);
      console.log(`   Notes written  : ${notes}`);
      console.log(`   Remaining      : ${raw - classif} to classify, ${classif - notes} to ingest, ${raw - gdrive} to upload\n`);
      return;
    }
    default:
      printHelp();
      process.exit(1);
  }
}

function printHelp() {
  console.log(`
Rugby Guy CLI
=============

Usage:
  node scripts/run.mjs rugby <command> [options]

Commands:
  sync        Full pipeline: extract -> classify -> ingest -> accounts
  extract     Fetch Instagram post metadata via yt-dlp
  classify    Classify posts against taxonomy
  ingest      Write Obsidian notes and regenerate glossary
  accounts    Rebuild Rugby/Coaching Accounts.md
  download    Download videos and upload to Google Drive
  publish     Export static gallery to dist/gallery.html
  web         Start coaching dashboard at http://localhost:5757
  status      Show pipeline coverage stats
`);
}

